import java.util.Arrays;
import java.util.Comparator;

public class Solution {

    private static final long MOD = 1_000_000_007L;

    /**
     * Calculates (base^exp) % MOD
     */
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    /**
     * Represents a segment defined by (ones, zeros).
     */
    static class Segment {
        long w; // count of '1's
        long z; // count of '0's
        long L; // total length w + z

        public Segment(long w, long z) {
            this.w = w;
            this.z = z;
            this.L = w + z;
        }
    }

    /**
     * Helper function to get the character (1 or 0) at a specific index k
     * within a segment (w, z).
     */
    private static int getChar(long w, long z, long k) {
        if (k < w) {
            return 1;
        }
        // Since k is guaranteed to be < w + z based on usage context, 
        // it must be in the zero block if not in the one block.
        return 0;
    }

    /**
     * Custom Comparator to decide if segment A should come before segment B
     * based on lexicographical comparison of A+B vs B+A.
     * We want A before B if A+B > B+A.
     */
    private static class SegmentComparator implements Comparator<Segment> {
        @Override
        public int compare(Segment A, Segment B) {
            long wA = A.w, zA = A.z, LA = A.L;
            long wB = B.w, zB = B.z, LB = B.L;

            // Compare S_AB vs S_BA character by character
            for (long k = 0; k < LA + LB; k++) {

