                    charAB = getChar(wA, zA, k);
                } else {
                    charAB = getChar(wB, zB, k - LA);
                }

                // Get character at index k in B+A
                int charBA;
                if (k < LB) {
                    charBA = getChar(wB, zB, k);
                } else {
                    charBA = getChar(wA, zA, k - LB);
                }

                if (charAB != charBA) {
                    // If AB is larger (1 > 0), A comes before B, return -1 (A is "less" in standard sort order 
                    // if we want descending sort, or +1 if we want ascending sort).
                    // We want descending order based on value, so A before B means A is "greater".
                    return (charAB == 1 ? -1 : 1); // If AB=1, BA=0, AB > BA, A should come first, so return -1 for standard sort logic (which sorts ascending). Wait, standard sort is ascending. If A should come first (be larger), we return a negative value.
