                                                   // If charAB < charBA (0 < 1), then A+B < B+A. A should be ordered after B. Return 1.
                    return (charAB == 1 ? -1 : 1);
                }
            }
            return 0; // Equal
        }
    }


    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;
        Segment[] segments = new Segment[n];

        for (int i = 0; i < n; i++) {
            segments[i] = new Segment(nums1[i], nums0[i]);
        }

        // Sort segments using the custom comparator
        Arrays.sort(segments, new SegmentComparator());

        long totalValue = 0;

        // Calculate the final value modulo 10^9 + 7
        for (Segment seg : segments) {
            long L_i = seg.L;
            long w_i = seg.w;

            // 1. Calculate Value(S_i) = 2^w_i - 1 mod M
            // Since w_i >= 0, 2^w_i - 1 is the value of 1^w_i.
            long val_seg = (power(2, w_i) - 1 + MOD) % MOD;

            // 2. Update totalValue: V_new = (V_old * 2^L_i + Value(S_i)) mod M

            // Calculate 2^L_i mod M
            long multiplier = power(2, L_i);

            // V_old * 2^L_i
            totalValue = (totalValue * multiplier) % MOD;

            // + Value(S_i)
            totalValue = (totalValue + val_seg) % MOD;
        }

        return totalValue;
    }
