                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    /**
     * Represents a binary segment defined by its counts of 1s and 0s.
     */
    private static class Segment {
        long ones;
        long zeros;

        public Segment(long ones, long zeros) {
            this.ones = ones;
            this.zeros = zeros;
        }
    }

    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;
        Segment[] segments = new Segment[n];

        for (int i = 0; i < n; i++) {
            segments[i] = new Segment(nums1[i], nums0[i]);
        }

        // Custom comparator based on the greedy strategy:
        // A precedes B if (a1 > b1) OR (a1 == b1 AND a0 < b0).
        Arrays.sort(segments, new Comparator<Segment>() {
            @Override
            public int compare(Segment a, Segment b) {
                // Primary sort key: ones (descending)
                if (a.ones != b.ones) {
                    // Since we want descending order, return positive if a.ones < b.ones
                    return Long.compare(b.ones, a.ones);
                }
                // Secondary sort key: zeros (ascending)
                return Long.compare(a.zeros, b.zeros);
            }
        });

        long totalValue = 0;
        long currentLength = 0;

        for (Segment seg : segments) {
            long a1 = seg.ones;
            long a0 = seg.zeros;
            long Li = a1 + a0;

            // 1. Update totalValue: Shift existing value left by Li positions (multiply by 2^Li)
            // V_new = V_old * 2^Li
            long shiftFactor = power(2, Li);
            totalValue = (totalValue * shiftFactor) % MOD;

            // 2. Calculate value contributed by the current segment S_i = 1^a1 0^a0
            // V_Si = (2^a1 - 1) * 2^a0

            long onesValue;
            if (a1 == 0) {
                // If a1=0, the segment is 0^a0, value is 0
                onesValue = 0;
            } else {
                // Calculate 2^a1 - 1 mod MOD
                long pow2a1 = power(2, a1);
                onesValue = (pow2a1 - 1 + MOD) % MOD;
            }

            // Calculate 2^a0 mod MOD
            long pow2a0 = power(2, a0);

            // V_Si = (onesValue * pow2a0) mod MOD
            long segmentValue = (onesValue * pow2a0) % MOD;

            // 3. Add segment value: V_total = V_new + V_Si
            totalValue = (totalValue + segmentValue) % MOD;

            // Update total length
            currentLength += Li;
        }

        return totalValue;
    }
}

