import java.util.Arrays;
import java.util.Comparator;

public class Solution {

    private static final long MOD = 1_000_000_007;

    // Helper class to represent a fragment
    static class Fragment {
        long n1;
        long n0;

        Fragment(long n1, long n0) {
            this.n1 = n1;
            this.n0 = n0;
        }
    }

    // Modular exponentiation (a^b % m)
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;
        Fragment[] fragments = new Fragment[n];

        for (int i = 0; i < n; i++) {
            fragments[i] = new Fragment(nums1[i], nums0[i]);
        }

        // Custom Comparator based on lexicographical comparison of S_A S_B vs S_B S_A
        Comparator<Fragment> comparator = (A, B) -> {
            long a1 = A.n1;
            long a0 = A.n0;
            long b1 = B.n1;
            long b0 = B.n0;

            // Rule 1: Compare leading 1s (a1 vs b1)
            if (a1 != b1) {
                // More 1s means larger number, so A comes first if a1 > b1
                return Long.compare(b1, a1); // Descending order of a1
            }

            // Rule 2: a1 = b1 = k. Compare R_A = 0^a0 1^k 0^b0 vs R_B = 0^b0 1^k 0^a0
            if (a0 == 0 && b0 == 0) {
                return 0; // Equal
            }

            // Case b: a0=0, b0>0. R_A starts with 1 (1^k...), R_B starts with 0 (0^b0...). A wins.
            if (a0 == 0 && b0 > 0) {
                return -1; // A comes before B
            }
            // Case c: a0>0, b0=0. R_A starts with 0 (0^a0...), R_B starts with 1 (1^k...). B wins.
            if (a0 > 0 && b0 == 0) {
                return 1; // B comes before A
            }

            // Case d: a0>0 and b0>0. Compare a0 vs b0.
            // If a0 < b0, R_A has a '1' sooner -> R_A > R_B. A wins.
            if (a0 != b0) {
                return Long.compare(a0, b0); // Ascending order of a0 (since smaller a0 means R_A > R_B)
            }

            // Case d: a0 = b0. Equal.
            return 0;
        };

        Arrays.sort(fragments, comparator);

        long result = 0;

        for (Fragment f : fragments) {
            long n1 = f.n1;
            long n0 = f.n0;
            long Li = n1 + n0;

            // 1. Calculate V_i (Value of the current fragment S_i)
            long Vi = 0;
            if (n1 > 0) {
                // Vi = (2^n1 - 1) * 2^n0 mod M

                // Term 1: 2^n1 - 1 mod M
                long pow2_n1 = power(2, n1);
                long T = (pow2_n1 - 1 + MOD) % MOD;

                // Term 2: 2^n0 mod M
                long P0 = power(2, n0);

                Vi = (T * P0) % MOD;
            }

            // 2. Update result: R_new = R_prev * 2^L_i + V_i mod M

            // Multiplier: 2^Li mod M
            long pow2_Li = power(2, Li);

            // R_prev * 2^Li
            long shifted_R = (result * pow2_Li) % MOD;

            // R_new = shifted_R + Vi
            result = (shifted_R + Vi) % MOD;
        }

        return result;
    }
}

